import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class AgentService {
  private readonly API = 'http://localhost:8080';

  constructor(private http: HttpClient) {}

  askQuestion(question: string): Observable<string> {
    const params = new HttpParams().set('question', question);
    return this.http.get(`${this.API}/askAgent`, {
      params,
      responseType: 'text',
      headers: { Accept: 'text/event-stream' }
    });
  }

  askWithFile(question: string, file?: File): Observable<string> {
    const formData = new FormData();
    formData.append('question', question);
    if (file) formData.append('file', file);
    return this.http.post(`${this.API}/askAgentWithFile`, formData, {
      responseType: 'text',
      headers: { Accept: 'text/event-stream' }
    });
  }

  // SSE streaming version
  streamQuestion(question: string): EventSource {
    const url = `${this.API}/askAgent?question=${encodeURIComponent(question)}`;
    return new EventSource(url);
  }

  streamWithFile(question: string, file?: File): Observable<string> {
    const formData = new FormData();
    formData.append('question', question);
    if (file) formData.append('file', file);
    return new Observable(observer => {
      this.http.post(`${this.API}/askAgentWithFile`, formData, {
        responseType: 'text'
      }).subscribe({
        next: (data) => observer.next(data),
        error: (err) => observer.error(err),
        complete: () => observer.complete()
      });
    });
  }
}
